import { useFormik } from "formik";
import TextField from "../../atoms/textfield/textfield";
import { useNavigate } from "react-router-dom";
import { PostPlayer } from "../../services/player-service";
import { Player } from "../../objects/player";

const AdminPlayer = ()  =>
{   
    const navigate = useNavigate();  
    const formik = useFormik({
        initialValues :{ firstname: "", surname: "", position : 0},
        onSubmit : values => {
            const player : Player = {id : 0, firstname: values.firstname, surname: values.surname, position : values.position}
            PostPlayer(player).then(formik.resetForm);
        }
    });

    return(
        <>       
            <div>           
                <form onSubmit={formik.handleSubmit}>
                    <div className="row">                        
                        <div className="col-3">
                            <TextField label="First Name" name="firstname" formik={formik}/>
                        </div>
                        <div className="col-3">
                            <TextField label="Surname" name="surname" formik={formik}/>
                        </div>  
                        <div className="col-3">
                            <TextField label="Surname" name="surname" formik={formik}/>
                        </div>                       
                    </div>
                    <div className="row">
                        <div className="col-2">
                            <button className="btn btn-secondary" onClick={()=> navigate('/Admin')}>Back</button>    
                            <button className="btn btn-primary" type="submit">Go</button>    
                        </div>
                    </div> 
                </form>            
            </div>
        </>
    );
}

export default AdminPlayer;
